SELECT id, name,
  (CASE WHEN json_extract(merged_profile_json, '$.way') IS NULL OR json_extract(merged_profile_json, '$.way') = '' THEN 1 ELSE 0 END) +
  (CASE WHEN json_extract(merged_profile_json, '$.overviewSalary.sal') IS NULL THEN 1 ELSE 0 END) +
  (CASE WHEN json_extract(merged_profile_json, '$.overviewProspect.main') IS NULL OR json_extract(merged_profile_json, '$.overviewProspect.main') = '' THEN 1 ELSE 0 END) +
  (CASE WHEN json_extract(merged_profile_json, '$.trivia') IS NULL THEN 1 ELSE 0 END)
  as missing_count
FROM jobs WHERE is_active=1 AND id NOT IN ('1765283278043521','1765283283500283','1765283708487303','1765283309704378','1765283292803601','176528331022350','1765283346646731','1765283536074109','1765283396344506','1765285562491567','1765284127013890','1765283469284852','1765284153577673','1765283475777136','1765284083754370','1765283459587278','1765283357861281','1765283469551675','1765283280870166','1765283717517364','1765283383162619','1765284473163806','1765283329480426','1765283294223537','1765283393158842','1765283393439394','1765283348496732','1765283362693974','1765283337718596','1765283331383599','1765283280202496','1765284216221323','1765283315034317','1765283284733631','1765283395276186','1765284037252808','1765283328079234','1765284036186296','1765283491867444','1765283308861305','1765283345735905','1765283280548221','1765284215921949','1765284049404293','1765283287536467','1765284473588878','1765283295729153','176528331355150','1765283319463731','1765284475702389','1765283465419996','1765284053919781','1765283392049802','1765283396081362','1765283328664135','1765283405233199','1765284217656435','1765284152811209','1765284216840412','1765283397656116','1765283321394772','1765283307925378','1765283283171475','1765283436042446','1765283345192165','1765284552912917','1765284120082557','1765284034719712','1765283278379444','176528334984955','1765283359273705','1765283456242935','1765283282842748','1765283362349517')
HAVING missing_count >= 3
ORDER BY missing_count DESC, name
LIMIT 20;